import React, { useState } from "react";
import { FaRegDotCircle, FaRegGrinStars, FaRegTimesCircle } from "react-icons/fa";

// Dummy SVGs (substitua depois por suas imagens)
function SvgDenteNormal() {
  return (
    <svg width="36" height="45" viewBox="0 0 36 45">
      <ellipse cx="18" cy="23" rx="14" ry="13" fill="#fff" stroke="#bbb" strokeWidth="2"/>
      <ellipse cx="18" cy="31" rx="13" ry="8" fill="#fbbf24" stroke="#ea580c" strokeWidth="1"/>
      <ellipse cx="18" cy="18" rx="9" ry="12" fill="#fff" opacity="0.2"/>
    </svg>
  );
}

function SvgDenteImplante() {
  return (
    <svg width="36" height="45" viewBox="0 0 36 45">
      <ellipse cx="18" cy="21" rx="14" ry="12" fill="#e5e7eb" stroke="#bbb" strokeWidth="2"/>
      <rect x="14" y="30" width="8" height="10" rx="2" fill="#a3a3a3" stroke="#555" strokeWidth="1"/>
      <ellipse cx="18" cy="29" rx="8" ry="4" fill="#e5e7eb" stroke="#bbb" strokeWidth="1"/>
      <line x1="17" y1="32" x2="17" y2="40" stroke="#555" strokeWidth="0.7"/>
      <line x1="19" y1="32" x2="19" y2="40" stroke="#555" strokeWidth="0.7"/>
    </svg>
  );
}

function SvgDenteCoroa() {
  return (
    <svg width="36" height="45" viewBox="0 0 36 45">
      <ellipse cx="18" cy="21" rx="14" ry="13" fill="#fff" stroke="#bbb" strokeWidth="2"/>
      <ellipse cx="18" cy="29" rx="12" ry="7" fill="#eab308" stroke="#ea580c" strokeWidth="1"/>
      <rect x="8" y="18" width="20" height="13" rx="7" fill="#eab308" opacity="0.8"/>
      <ellipse cx="18" cy="15" rx="9" ry="11" fill="#fff" opacity="0.2"/>
    </svg>
  );
}

function SvgDenteExtraido() {
  return (
    <svg width="36" height="45" viewBox="0 0 36 45">
      <ellipse cx="18" cy="23" rx="14" ry="13" fill="#f3f4f6" stroke="#bbb" strokeWidth="2"/>
      <line x1="10" y1="15" x2="26" y2="35" stroke="#d90429" strokeWidth="3"/>
      <line x1="26" y1="15" x2="10" y2="35" stroke="#d90429" strokeWidth="3"/>
    </svg>
  );
}

const DENTES_SUP = [18,17,16,15,14,13,12,11,21,22,23,24,25,26,27,28];
const DENTES_INF = [48,47,46,45,44,43,42,41,31,32,33,34,35,36,37,38];
const FACES = ["vestibular", "mesial", "coroa", "distal", "palatina"];
const ICONES = [
  { key: "normal", icon: <SvgDenteNormal />, label: "Normal" },
  { key: "implante", icon: <FaRegDotCircle />, label: "Implante" },
  { key: "coroa", icon: <FaRegGrinStars />, label: "Coroa" },
  { key: "extracao", icon: <FaRegTimesCircle />, label: "Extração" },
];

function getDenteImage(tipo) {
  switch (tipo) {
    case "implante": return <SvgDenteImplante />;
    case "coroa": return <SvgDenteCoroa />;
    case "extracao": return <SvgDenteExtraido />;
    default: return <SvgDenteNormal />;
  }
}

export default function OdontogramaDigitalComImagens() {
  const [facesSelecionadas, setFacesSelecionadas] = useState({});
  const [dentesSelecionados, setDentesSelecionados] = useState({});
  const [tipoDente, setTipoDente] = useState({});

  function toggleFace(dente, face) {
    setFacesSelecionadas(fs => ({
      ...fs,
      [dente]: {
        ...fs[dente],
        [face]: !fs[dente]?.[face]
      }
    }));
  }

  function toggleDenteCheckbox(dente) {
    const all = FACES.reduce((acc, face) => ({...acc, [face]: true}), {});
    setDentesSelecionados(ds => ({
      ...ds,
      [dente]: !ds[dente]
    }));
    setFacesSelecionadas(fs => ({
      ...fs,
      [dente]: !dentesSelecionados[dente] ? all : FACES.reduce((acc, f) => ({...acc, [f]: false}), {})
    }));
  }

  function handleIconeClick(dente, key) {
    setTipoDente(td => ({
      ...td,
      [dente]: td[dente] === key ? null : key
    }));
  }

  function renderDentes(arr) {
    return arr.map(num => (
      <div key={num} className="flex flex-col items-center mx-1">
        {/* Checkbox azul */}
        <input
          type="checkbox"
          checked={!!dentesSelecionados[num]}
          onChange={() => toggleDenteCheckbox(num)}
          className="accent-blue-600 mb-1"
          style={{width: 18, height: 18}}
        />
        {/* Imagem do dente */}
        <span style={{width: 36, height: 46, display: 'flex', justifyContent: 'center', alignItems: 'end'}}>
          {getDenteImage(tipoDente[num])}
        </span>
        {/* Quadrado anatômico */}
        <OdontoQuadrado
          faces={facesSelecionadas[num] || {}}
          onClickFace={face => toggleFace(num, face)}
        />
        {/* Número FDI */}
        <span className="text-xs mt-1">{num}</span>
        {/* Ícones de tratamento */}
        <div className="flex gap-1 mt-1">
          {ICONES.map(ic => (
            <button
              key={ic.key}
              title={ic.label}
              onClick={() => handleIconeClick(num, ic.key)}
              className={`border rounded p-1 ${tipoDente[num] === ic.key ? "bg-blue-100" : "bg-white"} hover:bg-blue-50`}
              style={{ fontSize: 18 }}
              type="button"
            >
              {ic.icon}
            </button>
          ))}
        </div>
      </div>
    ));
  }

  return (
    <div className="w-full max-w-6xl mx-auto p-4 bg-white rounded-xl shadow">
      <div className="text-lg font-bold text-center mb-4">Odontograma</div>
      <div className="flex justify-center mb-2">{renderDentes(DENTES_SUP)}</div>
      <div className="flex justify-center mt-2">{renderDentes(DENTES_INF)}</div>
      <div className="flex gap-6 mt-6 justify-center text-sm">
        <div>
          <span className="inline-block w-4 h-4 mr-1 align-middle rounded bg-orange-400 border border-gray-400" /> Selecionado
        </div>
        <div>
          <span className="inline-block w-4 h-4 mr-1 align-middle rounded bg-gray-300 border border-gray-400" /> Não selecionado
        </div>
      </div>
    </div>
  );
}

